// Pointer version
void SetInt(int *i) {
    (*i) = 5;
}
void main() {
    int x;
    SetInt(&x);
}

// Reference version -- identical assembly!
void SetInt(int &i) {
    i = 5;
}
void main() {
    int x;
    SetInt(x);
}

// With pointer: must use ->
struct Date { int X; };
void SetInt(Date *d) {
    d->X = 5;
}

// With reference: use . directly
struct Date { int X; };
void SetInt(Date &d) {
    d.X = 5;
}

int i = 10;
int *p;          // OK: pointer can be uninitialized
int &refI;       // COMPILE ERROR: uninitialized reference

int i = 10, j = 20;
int *p = &i;
p = &j;          // OK: pointer reassigned

int &refI = i;
&refI = j;       // COMPILE ERROR: cannot reassign reference

// Arithmetic
int *p2 = &i;
p2++;             // OK: pointer arithmetic
(&refI)++;        // COMPILE ERROR: no arithmetic on references

// Type casting
int i = 10;
char *p = (char *)&i;   // OK: pointer cast
char &refI = i;          // COMPILE ERROR: cannot cast reference

// Multiple indirection
int *p2 = &i;
int **p_to_p = &p2;     // OK: pointer to pointer
int & &ref_to_ref = i;  // COMPILE ERROR: no reference to reference

// Arrays
int *p3[100];            // OK: array of pointers
int &ref[100];           // COMPILE ERROR: array of references

class Math {
public:
    int   Add(int v1, int v2);           // Signature: Add(int, int)
    int   Add(int v1, int v2, int v3);   // Signature: Add(int, int, int)
    float Add(float v1, float v2);       // Signature: Add(float, float)
};

class Math {
public:
    int   Inc(int v1);
    float Inc(float v1);
};
Math m;
m.Inc(100);     // Exact match -> Inc(int)
m.Inc(1.0f);    // Exact match -> Inc(float)
m.Inc('a');     // Promotion: char -> int -> Inc(int)
m.Inc(1.0);     // ERROR: ambiguous (double -> int or float?)

// Single method: conversion allowed even with precision loss
class Math {
public:
    int Inc(char v1) { return v1 + 1; }
};
Math m;
m.Inc(1.0);  // WARNING: double -> char conversion, compiles

// Ambiguity: char promotes to int, but no Inc(int) exists
class Math {
public:
    int   Inc(short v1);
    float Inc(float v1);
};
m.Inc('a');  // ERROR: ambiguous

// const ignored for value types
class Math {
public:
    int Inc(int x) { return x + 2; }
    int Inc(const int x) { return x + 1; }  // ERROR: duplicate!
};

// const matters for pointers/references
class Math {
public:
    int Inc(int & x)       { return x + 2; }
    int Inc(const int & x) { return x + 1; }
};
Math m;
int x = 10;
m.Inc(x);     // -> Inc(int&)
m.Inc(100);   // -> Inc(const int&), 100 is constant

// The NULL macro in C++
#ifdef __cplusplus
    #define NULL 0       // Integer!
#else
    #define NULL ((void*)0)  // Pointer in C
#endif

void Print(int value) { printf("Number: %d\n", value); }
void Print(const char* text) { printf("Text: %s\n", text); }

void main() {
    Print(10);          // Output: Number: 10
    Print("C++ test");  // Output: Text: C++ test
    Print(NULL);        // Output: Number: 0  <-- NOT a pointer!
}

Print(nullptr);  // -> Print(const char*) -- correct!

// nullptr assignment rules:
int x = nullptr;        // ERROR: not an integer
bool b = nullptr;       // OK: b = false
const char* p = nullptr;// OK: null pointer

// nullptr with multiple pointer overloads:
void Print(const char* text) { ... }
void Print(int* value) { ... }
Print(nullptr);  // ERROR: ambiguous (const char* or int*?)

class Date {
private:
    int x;
public:
    int& GetX();           // returns modifiable reference
    const int& GetY();     // returns read-only reference
};

Date d;
d.GetX()++;   // OK: modifies x through reference
d.GetY()++;   // ERROR: cannot modify const reference
int x = d.GetY(); x++;  // OK: modifies local copy

int x;

// const value, non-const pointer
const int * ptr;
ptr = &x;     // OK: can change pointer
*ptr = 1;     // ERROR: cannot change value

// const pointer, non-const value
int * const ptr2 = &x;  // must initialize immediately
*ptr2 = 1;    // OK: can change value
ptr2 += 1;    // ERROR: cannot change pointer

// both const
const int * const ptr3 = &x;
*ptr3 = 1;    // ERROR
ptr3 += 1;    // ERROR

class Date {
private:
    int x;
    mutable int y;      // can be modified in const methods
    static int z;
public:
    const int& GetX() const {
        x = 0;          // ERROR: cannot modify x
        y = 0;          // OK: y is mutable
        z = 0;          // OK: z is static (not part of this)
        return x;
    }
    void ModifyOther(Date * d) const {
        d->x = 0;       // OK: d is a different object
        this->x = 0;    // ERROR: this is const
    }
};

// Friend function
class Date {
    int x;
public:
    Date(int value) : x(value) {}
    friend void PrintDate(Date &d);  // friend declaration
};

void PrintDate(Date &d) {
    printf("X = %d\n", d.x);  // OK: friend can access private
}

// Friend class -- ALL methods of Printer can access Date's privates
class Date {
    int x;
public:
    Date(int value) : x(value) {}
    friend class Printer;
};

class Printer {
public:
    void PrintDecimal(Date &d) { printf("x = %d\n", d.x); }     // OK
    void PrintHexadecimal(Date &d) { printf("x = %x\n", d.x); } // OK
};

// Friend method -- only ONE specific method from another class
class Data;  // forward declaration needed!

class Modifier {
public:
    void SetX(Data & d, int value);
};

class Data {
    int x;
    int& GetXRef() { return x; }
public:
    int GetX() { return x; }
    friend void Modifier::SetX(Data &, int);  // only this method
};

void Modifier::SetX(Data & d, int value) {
    d.GetXRef() = value;  // OK: can access private GetXRef()
}
